                  li x22, 0x9 # ECALL_SMODE
                  beq x12, x22, ecall_handler
                  li x22, 0xb # ECALL_MMODE
                  beq x12, x22, ecall_handler
                  li x22, 0x1
                  beq x12, x22, instr_fault_handler
                  li x22, 0x5
                  beq x12, x22, load_fault_handler
